#include<bits/stdc++.h>
using namespace std;
int n;
int a[1000010];
char ans[1000010],now[1000010];
deque<int> p,q;
void solve()
{
    int tot=2;
    while((!p.empty())||(!q.empty()))
    {
        if(q.empty())
        {
            if(p.front()!=p.back())
            {
                now[1]='Z';
                return;
            }
            now[tot]='L';
            now[2*n-tot+1]='L';
            p.pop_front();
            p.pop_back();
        }
        else if(p.empty())
        {
            if(q.front()!=q.back())
            {
                now[1]='Z';
                return;
            }
            now[tot]='R';
            now[2*n-tot+1]='R';
            q.pop_front();
            q.pop_back();
        }
        else
        {
            // printf("tot=%d p.back()=%d q.back()=%d p.front()=%d q.front()=%d\n",tot,p.back(),q.back(),p.front(),q.front());
            if(p.front()==p.back()&&p.size()>1)
            {
                now[tot]='L';
                now[n*2-tot+1]='L';
                p.pop_front();
                p.pop_back();
            }
            else if(p.back()==q.front())
            {
                now[tot]='L';
                now[n*2-tot+1]='R';
                q.pop_front();
                p.pop_back();
            }
            else if(q.back()==p.front())
            {
                now[tot]='R';
                now[n*2-tot+1]='L';
                p.pop_front();
                q.pop_back();
            }
            else if(q.front()==q.back()&&q.size()>1)
            {
                now[tot]='R';
                now[n*2-tot+1]='R';
                q.pop_front();
                q.pop_back();
            }
            else
            {
                now[1]='Z';
                return;
            }
        }
        tot++;
    }
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(ans,0,sizeof(ans));
        ans[1]='Y';
        scanf("%d",&n);
        int x=0;
        for(int i=1;i<=n*2;i++)
        {
            scanf("%d",&a[i]);
            if(i!=1&&a[i]==a[1])
            {
                x=i;
            }
        }
        memset(now,0,sizeof(now));
        now[1]='L';
        now[n*2]='L';
        p.clear();
        q.clear();
        for(int i=x-1;i>=2;i--)
        {
            p.push_back(a[i]);
        }
        for(int i=x+1;i<=n*2;i++)
        {
            q.push_back(a[i]);
        }
        solve();
        // printf("now=%s\n",now+1);
        if(strcmp(ans+1,now+1)>0)
        {
            memcpy(ans,now,sizeof(now));
        }
        x=0;
        for(int i=1;i<=n*2;i++)
        {
            if(i!=n*2&&a[i]==a[n*2])
            {
                x=i;
                break;
            }
        }
        memset(now,0,sizeof(now));
        now[1]='R';
        now[n*2]='L';
        p.clear();
        q.clear();
        for(int i=x-1;i>=1;i--)
        {
            p.push_back(a[i]);
        }
        for(int i=x+1;i<n*2;i++)
        {
            q.push_back(a[i]);
        }
        solve();
        if(strcmp(ans+1,now+1)>0)
        {
            memcpy(ans,now,sizeof(now));
        }
        if(ans[1]=='Y')
        {
            printf("-1\n");
        }
        else
        {
            printf("%s\n",ans+1);
        }
    }
    return 0;
}
